import{_ as e,c as o,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"マルチチャンネルとプラットフォーム | Clawdbot チュートリアル","description":"WhatsApp、Telegram、Slack、Discord、Google Chat、Signal、iMessage、LINE、WebChat、macOS、iOS、Android プラットフォームを含む、Clawdbot のマルチチャンネルシステムの設定と使用方法を学びます。","frontmatter":{"title":"マルチチャンネルとプラットフォーム | Clawdbot チュートリアル","sidebarTitle":"一般的なチャットツールへの接続","subtitle":"マルチチャンネルとプラットフォーム","description":"WhatsApp、Telegram、Slack、Discord、Google Chat、Signal、iMessage、LINE、WebChat、macOS、iOS、Android プラットフォームを含む、Clawdbot のマルチチャンネルシステムの設定と使用方法を学びます。","tags":["channels","platforms","integration"],"order":60},"headers":[],"relativePath":"ja/moltbot/moltbot/platforms/index.md","filePath":"ja/moltbot/moltbot/platforms/index.md"}'),r={name:"ja/moltbot/moltbot/platforms/index.md"};function i(s,a,n,h,d,g){return l(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="マルチチャンネルとプラットフォーム" tabindex="-1">マルチチャンネルとプラットフォーム <a class="header-anchor" href="#マルチチャンネルとプラットフォーム" aria-label="Permalink to &quot;マルチチャンネルとプラットフォーム&quot;">​</a></h1><p>Clawdbot は統一された Gateway 制御プレーンを通じて、複数の通信チャネルとプラットフォームをサポートし、あなたが使い慣れたインターフェースで AI アシスタントと対話できるようにします。</p><h2 id="章の概要" tabindex="-1">章の概要 <a class="header-anchor" href="#章の概要" aria-label="Permalink to &quot;章の概要&quot;">​</a></h2><p>本章では、Clawdbot がサポートするすべての通信チャネルとプラットフォームについて紹介します。これには、インスタントメッセージングアプリ（WhatsApp、Telegram、Slack、Discord など）、モバイルノード（iOS、Android）、デスクトップアプリ（macOS）が含まれます。これらのチャネルを設定し、AI アシスタントを日常のワークフローにシームレスに統合する方法を学びます。</p><h2 id="サブページナビゲーション" tabindex="-1">サブページナビゲーション <a class="header-anchor" href="#サブページナビゲーション" aria-label="Permalink to &quot;サブページナビゲーション&quot;">​</a></h2><h3 id="チャネルの概要" tabindex="-1">チャネルの概要 <a class="header-anchor" href="#チャネルの概要" aria-label="Permalink to &quot;チャネルの概要&quot;">​</a></h3><ul><li><strong><a href="./channels-overview/">マルチチャンネルシステムの概要</a></strong> - Clawdbot がサポートするすべての通信チャネルとその特徴について理解し、チャネル設定の基本概念を習得します。</li></ul><h3 id="インスタントメッセージングチャネル" tabindex="-1">インスタントメッセージングチャネル <a class="header-anchor" href="#インスタントメッセージングチャネル" aria-label="Permalink to &quot;インスタントメッセージングチャネル&quot;">​</a></h3><ul><li><strong><a href="./whatsapp/">WhatsApp</a></strong> - WhatsApp チャネル（Baileys ベース）を設定し使用し、デバイスのリンクとグループ管理をサポートします。</li><li><strong><a href="./telegram/">Telegram</a></strong> - Telegram チャネル（grammY Bot API ベース）を設定し使用し、Bot Token と Webhook を設定します。</li><li><strong><a href="./slack/">Slack</a></strong> - Slack チャネル（Bolt ベース）を設定し使用し、ワークスペースに統合します。</li><li><strong><a href="./discord/">Discord</a></strong> - Discord チャネル（discord.js ベース）を設定し使用し、サーバーとチャンネルをサポートします。</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Google Chat チャネルを設定し使用し、Google Workspace と統合します。</li><li><strong><a href="./signal/">Signal</a></strong> - Signal チャネル（signal-cli ベース）を設定し使用し、プライバシーを保護した通信を行います。</li><li><strong><a href="./imessage/">iMessage</a></strong> - iMessage チャネル（macOS 専用）を設定し使用し、macOS メッセージアプリと統合します。</li><li><strong><a href="./line/">LINE</a></strong> - LINE チャネル（Messaging API ベース）を設定し使用し、LINE ユーザーと対話します。</li></ul><h3 id="web-とネイティブアプリ" tabindex="-1">Web とネイティブアプリ <a class="header-anchor" href="#web-とネイティブアプリ" aria-label="Permalink to &quot;Web とネイティブアプリ&quot;">​</a></h3><ul><li><strong><a href="./webchat/">WebChat インターフェース</a></strong> - 内蔵の WebChat インターフェースを使用して AI アシスタントと対話し、外部チャネルの設定は不要です。</li><li><strong><a href="./macos-app/">macOS アプリ</a></strong> - macOS メニューバーアプリの機能について学びます（Voice Wake、Talk Mode、リモートコントロールを含む）。</li><li><strong><a href="./ios-node/">iOS ノード</a></strong> - iOS ノードを設定してデバイスのローカル操作を実行します（Camera、Canvas、Voice Wake）。</li><li><strong><a href="./android-node/">Android ノード</a></strong> - Android ノードを設定してデバイスのローカル操作を実行します（Camera、Canvas）。</li></ul><h2 id="学習パスの提案" tabindex="-1">学習パスの提案 <a class="header-anchor" href="#学習パスの提案" aria-label="Permalink to &quot;学習パスの提案&quot;">​</a></h2><p>あなたの使用シナリオに応じて、以下の学習順序をお勧めします。</p><h3 id="初心者向けクイックスタート" tabindex="-1">初心者向けクイックスタート <a class="header-anchor" href="#初心者向けクイックスタート" aria-label="Permalink to &quot;初心者向けクイックスタート&quot;">​</a></h3><p>初めて Clawdbot を使用する場合、以下の順序で学習することをお勧めします。</p><ol><li><strong><a href="./channels-overview/">マルチチャンネルシステムの概要</a></strong> - まず全体のアーキテクチャとチャネルの概念を理解します</li><li><strong><a href="./webchat/">WebChat インターフェース</a></strong> - 最も簡単な方法で、設定なしで使用を開始できます</li><li><strong>一般的なチャネルを 1 つ選択</strong> - あなたの日常の習慣に応じて選択します： <ul><li>日常のチャット → <a href="./whatsapp/">WhatsApp</a> または <a href="./telegram/">Telegram</a></li><li>チーム協力 → <a href="./slack/">Slack</a> または <a href="./discord/">Discord</a></li><li>macOS ユーザー → <a href="./imessage/">iMessage</a></li></ul></li></ol><h3 id="モバイル統合" tabindex="-1">モバイル統合 <a class="header-anchor" href="#モバイル統合" aria-label="Permalink to &quot;モバイル統合&quot;">​</a></h3><p>モバイルデバイスで Clawdbot を使用したい場合：</p><ol><li><strong><a href="./ios-node/">iOS ノード</a></strong> - iPhone/iPad 上のローカル機能を設定します</li><li><strong><a href="./android-node/">Android ノード</a></strong> - Android デバイス上のローカル機能を設定します</li><li><strong><a href="./macos-app/">macOS アプリ</a></strong> - macOS アプリをコントロールセンターとして使用します</li></ol><h3 id="エンタープライズデプロイメント" tabindex="-1">エンタープライズデプロイメント <a class="header-anchor" href="#エンタープライズデプロイメント" aria-label="Permalink to &quot;エンタープライズデプロイメント&quot;">​</a></h3><p>チーム環境にデプロイする必要がある場合：</p><ol><li><strong><a href="./slack/">Slack</a></strong> - チームワークスペースに統合します</li><li><strong><a href="./discord/">Discord</a></strong> - コミュニティサーバーを構築します</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Google Workspace と統合します</li></ol><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>本章の学習を開始する前に、以下を完了することをお勧めします。</p><ul><li><strong><a href="./../start/getting-started/">クイックスタート</a></strong> - Clawdbot のインストールと基本設定を完了します</li><li><strong><a href="./../start/onboarding-wizard/">設定ウィザード</a></strong> - ウィザードを通じて Gateway とチャネルの基本設定を完了します</li></ul><div class="tip custom-block"><p class="custom-block-title">ヒント</p><p>設定ウィザードを完了している場合、一部のチャネルは既に自動的に設定されている可能性があります。重複する設定手順をスキップして、特定のチャネルの高度な機能を確認できます。</p></div><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>本章の学習を完了した後、以下を引き続き探索できます。</p><ul><li><strong><a href="./../advanced/models-auth/">AI モデルと認証設定</a></strong> - 異なる AI モデルプロバイダーを設定します</li><li><strong><a href="./../advanced/session-management/">セッション管理とマルチエージェント</a></strong> - セッション分離とサブエージェントの協調について学びます</li><li><strong><a href="./../advanced/tools-browser/">ツールシステム</a></strong> - ブラウザ自動化、コマンド実行などのツールを使用します</li></ul><h2 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to &quot;よくある質問&quot;">​</a></h2><details class="details custom-block"><summary>複数のチャネルを同時に使用できますか？</summary><p>はい！Clawdbot は複数のチャネルを同時に有効化できます。異なるチャネルでメッセージの送受信ができ、すべてのメッセージは統一された Gateway を通じて処理されます。</p></details><details class="details custom-block"><summary>どのチャネルが最も推奨されますか？</summary><p>これはあなたの使用シナリオによります：</p><ul><li><strong>WebChat</strong> - 最もシンプルで、設定は不要です</li><li><strong>WhatsApp</strong> - 友人や家族とのチャットに適しています</li><li><strong>Telegram</strong> - Bot API が安定しており、自動返信に適しています</li><li><strong>Slack/Discord</strong> - チーム協力に適しています</li></ul></details><details class="details custom-block"><summary>チャネルの設定に費用はかかりますか？</summary><p>多くのチャネル自体は無料ですが、一部のチャネルにはコストがかかる場合があります：</p><ul><li>WhatsApp Business API - 料金が発生する可能性があります</li><li>Google Chat - Google Workspace アカウントが必要です</li><li>その他のチャネル - 通常は無料で、Bot Token の申請のみが必要です</li></ul></details>',33)])])}const p=e(r,[["render",i]]);export{m as __pageData,p as default};
